parameters.jsCode:
const fillers = [
    "firstname","lastname","owner","founder","ceo","admin","info",
    "office","contact","support","help","our","managing.partner","team","blastname"
];

let output = [];
let seen = {}; // track per domain to dedupe

for (const item of items) {
    // Correct path to emails
    const company = item.json.output?.company || "Unknown Company";
    const domain = item.json.output?.domain || "unknown.com";
    const emails = item.json.output?.owner_emails || [];

    if (!emails.length) continue; // skip if no emails

    if (!seen[domain]) seen[domain] = new Set();

    for (const email of emails) {
        if (!email) continue; // skip undefined/null

        const local = email.split("@")[0].toLowerCase();

        // Skip any email that contains a filler anywhere
        if (fillers.some(f => local.includes(f))) continue;

        // Skip duplicates for same first-name per company
        const firstNamePart = local.split(/[.\-_]/)[0]; 
        if (seen[domain].has(firstNamePart)) continue;
        seen[domain].add(firstNamePart);

        output.push({
            json: {
                company,
                domain,
                email
            }
        });
    }
}

return output;
